module RefModule (
    clk,
    rst,
    data_in,
    enable,
    data_out
);

    input clk, rst, enable;
    input [3:0] data_in;
    output reg [3:0] data_out;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (rst) begin
            data_out <= 4'b0;
        end
        else if (enable) begin
            data_out <= data_in;
        end
    end

endmodule
